package com.fasterxml.jackson.dataformat.xml.deser;

import java.io.IOException;

import com.fasterxml.jackson.core.JsonParser;
import com.fasterxml.jackson.core.JsonToken;
import com.fasterxml.jackson.databind.DeserializationContext;
import com.fasterxml.jackson.databind.deser.std.StringDeserializer;

/**
 * Custom String deserializer that can handle "empty Object" (START_OBJECT -> END_OBJECT)
 * sequence, and return empty String ("") for it.
 * This is necessary because XML parser may expose empty elements as Empty Objects
 * to support deserialization of Beans from empty elements.
 */
public class XmlStringDeserializer extends StringDeserializer
{
    private static final long serialVersionUID = 1L;

    public XmlStringDeserializer() { super(); }

    @Override
    public String deserialize(JsonParser p, DeserializationContext ctxt) throws IOException {
        if (p.getCurrentToken() == JsonToken.START_OBJECT) {
            JsonToken t = p.nextToken();
            if (t == JsonToken.END_OBJECT) {
                return "";
            }
            // unexpected content in what should be empty object for String
             return (String) ctxt.handleUnexpectedToken(String.class, p);
        }
        return super.deserialize(p, ctxt);
    }
}

